        "id": "01f1093d706e18b182e88b21227de8ad",
        "question": [
          "What is my forecasted spend for the year?"
        ],
        "sql": [
          "WITH aggregated_spend AS (\n",
          "SELECT CAST (usage_start_time AS DATE) AS usage_date,\n",
          "SUM(usage_quantity * pricing.effective_list.default) AS total_spend\n",
          "FROM\n",
          "system.billing.usage u\n",
          "JOIN system. billing. list_prices p ON\n",
          "u.sku_name = p.sku_name WHERE u.usage_end_time >= p.price_start_time  AND (p.price_end_time IS NULL OR u.usage_end_time < p.price_end_time)\n",
          "GROUP BY\n",
          "1)\n",
          "\n",
          "SELECT * FROM ai_forecast(\n",
          "TABLE (aggregated_spend), horizon => '2025-12-31',\n",
          "time_col => 'usage_date',\n",
          "value_col => 'total_spend'\n",
          ")\n"
        ]
      },
      {
        "id": "01f1093d70731579a8b55ce960a3352a",
        "question": [
          "What is the cost of Materialized View and Streaming Table this month?"
        ],
        "sql": [
          "SELECT\n",
          "  SUM(u.usage_quantity * p.pricing.effective_list.`default`) AS list_cost\n",
          "FROM system.billing.usage AS u\n",
          "JOIN system.billing.list_prices AS p\n",
          "  ON  u.sku_name = p.sku_name\n",
          "  AND u.usage_start_time >= p.price_start_time\n",
          "  AND (p.price_end_time IS NULL OR u.usage_end_time < p.price_end_time)  -- open-ended / right-open\n",
          "WHERE u.billing_origin_product = 'SQL'\n",
          "  AND u.usage_metadata.dlt_pipeline_id IS NOT NULL\n",
          "  AND u.usage_date >= date_trunc('MONTH', current_date())\n",
          "  AND u.usage_date <  add_months(date_trunc('MONTH', current_date()), 1);"
        ],
        "usage_guidance": [
          "Use when asked to calculate cost of Materialized View (MV) and Streaming Table (ST)"
        ]
      },
      {
        "id": "01f1093d70741a8185823b60920859f5",
