          "Who are our top 5 users this month?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH usage_with_user AS (\n",
              "  SELECT\n",
              "    COALESCE(usage.identity_metadata.run_as, usage.identity_metadata.owned_by, usage.identity_metadata.created_by) AS user,\n",
              "    usage.usage_quantity * list_prices.pricing.effective_list.default AS list_cost,\n",
              "    usage.usage_date\n",
              "  FROM system.billing.usage\n",
              "  JOIN system.billing.list_prices\n",
              "    ON list_prices.sku_name = usage.sku_name\n",
              "  AND usage.usage_end_time >= list_prices.price_start_time\n",
              "    AND (list_prices.price_end_time IS NULL OR usage.usage_end_time < list_prices.price_end_time)\n",
              "    WHERE usage.usage_date >= date_trunc('month', current_date())\n",
              ")\n",
              "\n",
              "SELECT\n",
              "  user,\n",
              "  SUM(list_cost) AS total_list_cost\n",
              "FROM usage_with_user\n",
              "GROUP BY user\n",
              "ORDER BY total_list_cost DESC\n",
              "LIMIT 5"
            ]
          }
        ]
