      {
        "id": "01f1093d70a914279338dff973752bcf",
        "question": [
          "How much are we forecasted to spend in the next 90 days, not including today?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH aggregated_spend AS (\n",
              "  SELECT\n",
              "    usage_date AS usage_date,\n",
              "    SUM(usage_quantity * pricing.effective_list.default) AS total_spend\n",
              "  FROM\n",
              "    system.billing.usage u\n",
              "      JOIN system.billing.list_prices p\n",
              "        ON u.sku_name = p.sku_name\n",
              "  WHERE\n",
              "    u.usage_end_time >= p.price_start_time\n",
              "    AND (\n",
              "      p.price_end_time IS NULL\n",
              "      OR u.usage_end_time < p.price_end_time\n",
              "    )\n",
              "  AND  usage_date < current_date\n",
              "  GROUP BY\n",
              "    1\n",
              ")\n",
              "SELECT\n",
              "  SUM(total_spend_forecast)\n",
              "FROM\n",
              "  ai_forecast(\n",
              "    TABLE(aggregated_spend),\n",
              "    horizon => date_add(current_date, 90),\n",
              "    time_col => 'usage_date',\n",
              "    value_col => 'total_spend'\n",
              "  )\n",
              "WHERE\n",
              "  usage_date > current_date"
            ]
          }
        ]
